/// Array element type.
enum mlx_dtype_ {
  MLX_BOOL(0),
  MLX_UINT8(1),
  MLX_UINT16(2),
  MLX_UINT32(3),
  MLX_UINT64(4),
  MLX_INT8(5),
  MLX_INT16(6),
  MLX_INT32(7),
  MLX_INT64(8),
  MLX_FLOAT16(9),
  MLX_FLOAT32(10),
  MLX_FLOAT64(11),
  MLX_BFLOAT16(12),
  MLX_COMPLEX64(13);

  final int value;
  const mlx_dtype_(this.value);

  static mlx_dtype_ fromValue(int value) => switch (value) {
    0 => MLX_BOOL,
    1 => MLX_UINT8,
    2 => MLX_UINT16,
    3 => MLX_UINT32,
    4 => MLX_UINT64,
    5 => MLX_INT8,
    6 => MLX_INT16,
    7 => MLX_INT32,
    8 => MLX_INT64,
    9 => MLX_FLOAT16,
    10 => MLX_FLOAT32,
    11 => MLX_FLOAT64,
    12 => MLX_BFLOAT16,
    13 => MLX_COMPLEX64,
    _ => throw ArgumentError('Unknown value for mlx_dtype_: $value'),
  };
}

